    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xEF013DA9AEABBE05ULL + 0xFACD9FFD84142BB1ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0x9226EBE9504A7FCFULL + 0xD9714DE6D67940BFULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xA19EC73FB4D768DDULL + 0x9E4FDA640D35CF02ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xEB0CB155A8E46873ULL + 0xA885958EEB7574CBULL);
