    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0xE3CA4E7C77FD7177ULL + 0xA47B0DC1A74C80E7ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xF3D21C34F1F3771DULL + 0xD4C4EBAD55C9A44FULL);
