            aCross = TwistMix64::DiffuseC(((aCross ^ aDomainWordCross) ^ aNonceWordN));
            //
            aScatter = (RotL64(aIngress, 11U) ^ RotL64(aCross, 56U)) + (RotL64(aPrevious, 37U) ^ RotL64(aCarry, 23U));
