            aOrbiterJ = (((aWandererA + RotL64(aScatter, 35U)) + 4809192776429682319U) + aOrbiterAssignSaltB[((aIndex + 8U)) & S_SALT1]) + aNonceWordA;
            aOrbiterE = (aWandererC + RotL64(aIngress, 53U)) + 5576603692574369341U;
