            aOrbiterB = ((aOrbiterB ^ aOrbiterE) ^ 3308740700728172984U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 15290400462887712083U), 11U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterC) + 9535358833412446771U;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 11192312491731312451U;
            aOrbiterE = RotL64((aOrbiterE * 17405609148475445743U), 19U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterJ) + 14850451970047190039U;
            aOrbiterI = (aOrbiterI ^ aOrbiterF) ^ 11932493299452443256U;
            aOrbiterI = RotL64((aOrbiterI * 7964808728820467795U), 5U);
            //
            aOrbiterD = (((aOrbiterD + aOrbiterK) + 5972619895614731870U) + aOrbiterUpdateSaltC[((aIndex + 23U)) & S_SALT1]) + aNonceWordK;
            aOrbiterF = (aOrbiterF ^ aOrbiterD) ^ 17174497535809891690U;
            aOrbiterF = RotL64((aOrbiterF * 15471084511364572533U), 23U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterG) + 17412894714378898351U;
            aOrbiterK = (aOrbiterK ^ aOrbiterI) ^ 14675615208706549810U;
            aOrbiterK = RotL64((aOrbiterK * 7864845089606499769U), 35U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 16116792108013658523U;
