            //
            aOrbiterH = (aOrbiterH + aOrbiterI) + 17337264966818542841U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterH) ^ 7004462033775827275U) ^ aOrbiterUpdateSaltE[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 11943575980344402681U), 47U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterF) + 17499850384482055438U;
            aOrbiterH = (aOrbiterH ^ aOrbiterC) ^ 1839357713256560566U;
