            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterG, 19U));
            aIngress = aIngress + RotL64(aOrbiterI, 13U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererF = aWandererF + (((RotL64(aCross, 35U) + aOrbiterA) + RotL64(aOrbiterF, 43U)) + aWandererUpdateSaltB[(((31U - aIndex) + 4U)) & S_SALT1]);
            aWandererJ = aWandererJ ^ ((RotL64(aScatter, 23U) + aOrbiterJ) + RotL64(aOrbiterK, 26U));
            aWandererG = aWandererG + (((RotL64(aPrevious, 21U) + aOrbiterI) + RotL64(aOrbiterE, 5U)) + aNonceWordL);
